mapper.select:
SELECT log_id, requested_by, request_type, input_data_json, prediction_result_json, created_at FROM ai_prediction_log
(requested_by LIKE CONCAT('%', #{q}, '%') OR request_type LIKE CONCAT('%', #{q}, '%') OR input_data_json LIKE CONCAT('%', #{q}, '%') OR prediction_result_json LIKE CONCAT('%', #{q}, '%'))
AND created_at >= #{from}
AND created_at < DATE_ADD(#{to}, INTERVAL 1 DAY)
ORDER BY created_at DESC LIMIT #{cri.perPageNum} OFFSET #{cri.pageStart}
